1	// Apify client wrapper for Marketify edge functions.
2	//
3	// Contract: runTikTokProfile(handle, { waitSecs? })    -> { runId, datasetId, status }
4	//           runInstagramDetails(handle, { waitSecs? }) -> { runId, datasetId, status }
5	//           runInstagramPosts(handle, { waitSecs? })   -> { runId, datasetId, status }
6	// Actors:   `clockworks/tiktok-scraper` (REST slug `clockworks~tiktok-scraper`),
7	//           `apify/instagram-scraper`  (REST slug `apify~instagram-scraper`).
8	//           Actor input shapes per docs/tech-architecture.md §3b / §3c.
9	// Endpoint: POST https://api.apify.com/v2/acts/<slug>/runs?token=<key>&waitForFinish=<secs>.
10	//           The waitForFinish query parameter makes Apify block up to `waitSecs`
11	//           seconds before returning the run object, so callers can either parse
12	//           results inline (status=SUCCEEDED) or fall back to webhook-completed
13	//           delivery when the wait expires (status=RUNNING).
14	// Secret:   APIFY_KEY env var (the Apify API token).
15	// Auth:     no inbound auth requirement — this module is a building block for
16	//           edge functions that have already verified JWT.
17	
18	const APIFY_API_BASE = "https://api.apify.com/v2";
19	
20	const TIKTOK_ACTOR_SLUG = "clockworks~tiktok-scraper";
21	const INSTAGRAM_ACTOR_SLUG = "apify~instagram-scraper";
22	
23	const DEFAULT_WAIT_SECS = 60;
24	
25	export interface ApifyRunResult {
26	  runId: string;
27	  datasetId: string;
28	  status: string;
29	}
30	
31	export interface ApifyRunOptions {
32	  waitSecs?: number;
33	}
34	
35	function readApifyKey(): string {
36	  const k = Deno.env.get("APIFY_KEY");
37	  if (!k) throw new Error("APIFY_KEY is not set");
38	  return k;
39	}
40	
41	async function startActorRun(
42	  slug: string,
43	  input: Record<string, unknown>,
44	  waitSecs: number,
45	): Promise<ApifyRunResult> {
46	  if (!Number.isFinite(waitSecs) || waitSecs < 0) {
47	    throw new Error("waitSecs must be a non-negative finite number");
48	  }
49	  const url = new URL(`${APIFY_API_BASE}/acts/${slug}/runs`);
50	  url.searchParams.set("token", readApifyKey());
51	  url.searchParams.set("waitForFinish", String(Math.floor(waitSecs)));
52	
53	  const res = await fetch(url.toString(), {
54	    method: "POST",
55	    headers: { "content-type": "application/json" },
56	    body: JSON.stringify(input),
57	  });
58	
59	  if (!res.ok) {
60	    const body = await res.text();
61	    throw new Error(
62	      `Apify actor '${slug}' run failed: ${res.status} ${res.statusText} ${body}`,
63	    );
64	  }
65	
66	  const payload = (await res.json()) as {
67	    data?: { id?: string; defaultDatasetId?: string; status?: string };
68	  };
69	  const data = payload.data;
70	  if (
71	    !data ||
72	    typeof data.id !== "string" ||
73	    typeof data.defaultDatasetId !== "string" ||
74	    typeof data.status !== "string"
75	  ) {
76	    throw new Error(
77	      `Apify actor '${slug}' returned malformed run payload`,
78	    );
79	  }
80	  return {
81	    runId: data.id,
82	    datasetId: data.defaultDatasetId,
83	    status: data.status,
84	  };
85	}
86	
87	export async function runTikTokProfile(
88	  handle: string,
89	  options: ApifyRunOptions = {},
90	): Promise<ApifyRunResult> {
91	  if (!handle) throw new Error("handle is required");
92	  return await startActorRun(
93	    TIKTOK_ACTOR_SLUG,
94	    {
95	      profiles: [handle],
96	      resultsPerPage: 10,
97	      profileScrapeSections: ["videos"],
98	      profileSorting: "latest",
99	      excludePinnedPosts: true,
100	      shouldDownloadVideos: false,
101	      shouldDownloadCovers: false,
102	      shouldDownloadSubtitles: false,
103	    },
104	    options.waitSecs ?? DEFAULT_WAIT_SECS,
105	  );
106	}
107	
108	export async function runInstagramDetails(
109	  handle: string,
110	  options: ApifyRunOptions = {},
111	): Promise<ApifyRunResult> {
112	  if (!handle) throw new Error("handle is required");
113	  return await startActorRun(
114	    INSTAGRAM_ACTOR_SLUG,
115	    {
116	      directUrls: [`https://www.instagram.com/${handle}/`],
117	      resultsType: "details",
118	      resultsLimit: 1,
119	      addParentData: false,
120	    },
121	    options.waitSecs ?? DEFAULT_WAIT_SECS,
122	  );
123	}
124	
125	export async function runInstagramPosts(
126	  handle: string,
127	  options: ApifyRunOptions = {},
128	): Promise<ApifyRunResult> {
129	  if (!handle) throw new Error("handle is required");
130	  return await startActorRun(
131	    INSTAGRAM_ACTOR_SLUG,
132	    {
133	      directUrls: [`https://www.instagram.com/${handle}/`],
134	      resultsType: "posts",
135	      resultsLimit: 10,
136	      addParentData: false,
137	    },
138	    options.waitSecs ?? DEFAULT_WAIT_SECS,
139	  );
140	}
