1	// Unit tests for the Apify client wrapper.
2	//
3	// Replace `globalThis.fetch` with a spy, then assert each wrapper function
4	// constructs the correct URL (actor slug + token + waitForFinish) and POST
5	// body (actor input shape per docs/tech-architecture.md §3b / §3c).
6	//
7	// Run: deno test --allow-env supabase/functions/_shared/apify.test.ts
8	
9	import {
10	  assert,
11	  assertEquals,
12	  assertRejects,
13	} from "jsr:@std/assert@1";
14	
15	import {
16	  runInstagramDetails,
17	  runInstagramPosts,
18	  runTikTokProfile,
19	} from "./apify.ts";
20	
21	type Captured = { url: string; init: RequestInit };
22	
23	function installFetchSpy(
24	  response: Record<string, unknown>,
25	  init: ResponseInit = { status: 201 },
26	): { captured: Captured[]; restore: () => void } {
27	  const original = globalThis.fetch;
28	  const captured: Captured[] = [];
29	  globalThis.fetch = ((input: string | URL | Request, reqInit?: RequestInit) => {
30	    const url = typeof input === "string"
31	      ? input
32	      : input instanceof URL
33	      ? input.toString()
34	      : input.url;
35	    captured.push({ url, init: reqInit ?? {} });
36	    return Promise.resolve(
37	      new Response(JSON.stringify(response), {
38	        status: init.status ?? 201,
39	        headers: { "content-type": "application/json" },
40	      }),
41	    );
42	    // deno-lint-ignore no-explicit-any -- fetch has many overloads; the spy matches the subset we use
43	  }) as any;
44	  return { captured, restore: () => { globalThis.fetch = original; } };
45	}
46	
47	function stubRunResponse() {
48	  return {
49	    data: {
50	      id: "run_abc123",
51	      defaultDatasetId: "ds_xyz789",
52	      status: "SUCCEEDED",
53	    },
54	  };
55	}
56	
57	function setApifyKey(value: string | null) {
58	  if (value === null) Deno.env.delete("APIFY_KEY");
59	  else Deno.env.set("APIFY_KEY", value);
60	}
61	
62	Deno.test("runTikTokProfile builds the tiktok actor run request", async () => {
63	  setApifyKey("test-token");
64	  const { captured, restore } = installFetchSpy(stubRunResponse());
65	  try {
66	    const result = await runTikTokProfile("charlidamelio");
67	
68	    assertEquals(captured.length, 1);
69	    const url = new URL(captured[0].url);
70	    assertEquals(url.origin + url.pathname,
71	      "https://api.apify.com/v2/acts/clockworks~tiktok-scraper/runs");
72	    assertEquals(url.searchParams.get("token"), "test-token");
73	    assertEquals(url.searchParams.get("waitForFinish"), "60");
74	
75	    assertEquals(captured[0].init.method, "POST");
76	    const headers = new Headers(captured[0].init.headers as HeadersInit);
77	    assertEquals(headers.get("content-type"), "application/json");
78	
79	    const body = JSON.parse(captured[0].init.body as string);
80	    assertEquals(body, {
81	      profiles: ["charlidamelio"],
82	      resultsPerPage: 10,
83	      profileScrapeSections: ["videos"],
84	      profileSorting: "latest",
85	      excludePinnedPosts: true,
86	      shouldDownloadVideos: false,
87	      shouldDownloadCovers: false,
88	      shouldDownloadSubtitles: false,
89	    });
90	
91	    assertEquals(result, {
92	      runId: "run_abc123",
93	      datasetId: "ds_xyz789",
94	      status: "SUCCEEDED",
95	    });
96	  } finally {
97	    restore();
98	  }
99	});
